const config = {
  supabaseUrl: $env.SUPABASE_URL || '여기에_SUPABASE_URL_입력',
  supabaseKey: $env.SUPABASE_SERVICE_ROLE_KEY || '여기에_SERVICE_ROLE_KEY_입력',
  anthropicApiKey: $env.ANTHROPIC_API_KEY || '여기에_ANTHROPIC_API_KEY_입력',
  openaiApiKey: $env.OPENAI_API_KEY || '',
  slackWebhookUrl: $env.SLACK_WEBHOOK_URL || '여기에_SLACK_WEBHOOK_URL_입력',
  naverClientId: $env.NAVER_CLIENT_ID || '',
  naverClientSecret: $env.NAVER_CLIENT_SECRET || '',
  // Claude를 사용할지 OpenAI를 사용할지 선택
  useClaudeApi: true,
};

return [{ json: config }];

const articles = $input.all().map(item => item.json);

// 카테고리별 그룹핑
const CATEGORY_LABEL = {
  ai_business: 'AI 비즈니스',
  startup: '창업·부업',
  policy: '정책·지원사업',
};

const grouped = { ai_business: [], startup: [], policy: [] };
for (const a of articles) {
  if (grouped[a.category]) {
    grouped[a.category].push(a);
  }
}

// 키워드별 기사 수 집계
const keywordCounts = {};
for (const [category, catArticles] of Object.entries(grouped)) {
  keywordCounts[category] = {};
  for (const a of catArticles) {
    // keyword_id 기반으로 카운트 (실제 keyword 텍스트가 없으므로 제목 기반 분석)
    const titleWords = a.title.split(/\s+/).slice(0, 3).join(' ');
    keywordCounts[category][titleWords] = (keywordCounts[category][titleWords] || 0) + 1;
  }
}

// 카테고리별 요약 생성
const summaryParts = Object.entries(grouped).map(([category, catArticles]) => {
  const label = CATEGORY_LABEL[category] || category;
  const headlines = catArticles
    .slice(0, 10)
    .map(a => `- ${a.title}`)
    .join('\n') || '(수집된 기사 없음)';

  // 상위 키워드 추출 (제목 빈도 기반)
  const topKeywords = Object.entries(keywordCounts[category] || {})
    .sort((a, b) => b[1] - a[1])
    .slice(0, 5)
    .map(([kw, count]) => `${kw}: 기사 ${count}건`)
    .join('\n') || '(분석 대상 키워드 없음)';

  return `## ${label}\n[주요 키워드]\n${topKeywords}\n[최근 헤드라인]\n${headlines}`;
}).join('\n\n');

return [{
  json: {
    summary: summaryParts,
    totalArticles: articles.length,
    byCategory: {
      ai_business: grouped.ai_business.length,
      startup: grouped.startup.length,
      policy: grouped.policy.length,
    }
  }
}];

const config = $('⚙️ 설정 로드').first().json;
const analysis = $input.first().json;

const systemPrompt = `당신은 코아뉴스의 편집 데스크 보조입니다. 코아뉴스는 다음 4개 섹션을 운영합니다:
- AI 비즈니스: 최신 AI 기술·활용 사례·업무 자동화
- 창업·부업: 창업 트렌드, 온라인 수익화, 1인 기업 실전 정보
- 정책·지원사업: 정부·공공기관 지원사업을 쉽게 풀어주는 실용 정보
- 칼럼·인터뷰: 현장 경험과 전문가 분석 기반의 심층 시각, 전문가·당사자 인터뷰

다음 기준으로 소재를 제안하세요:
- AI 비즈니스 2건, 창업·부업 2건, 정책·지원사업 2건
- 칼럼 1건: 지속되는 주요 키워드에서 선정
- 인터뷰 1건: 새롭게 떠오르는 키워드 또는 당사자가 명확한 이슈에서 선정하고, 섭외할 인터뷰이 유형을 interviewee 필드에 구체적으로 제안 (예: "AI 도입 중소기업 대표")
- 반드시 8건을 제안

응답은 반드시 다음 JSON 형식으로 해주세요:
{
  "suggestions": [
    {
      "category": "ai_business|startup|policy|column",
      "format": "article|column|interview",
      "title": "제안 기사 제목",
      "angle": "기사 각도/관점 설명",
      "keywords": ["키워드1", "키워드2"],
      "reference_headlines": ["참고한 헤드라인1"],
      "quadrant": "blue_ocean|hot|media_led|null",
      "interviewee": "섭외 대상 또는 null"
    }
  ]
}`;

const userMessage = `[오늘의 카테고리별 키워드 분석]\n\n${analysis.summary}\n\n총 수집 기사: ${analysis.totalArticles}건 (AI ${analysis.byCategory.ai_business}건, 창업 ${analysis.byCategory.startup}건, 정책 ${analysis.byCategory.policy}건)`;

return [{
  json: {
    systemPrompt,
    userMessage,
    useClaudeApi: config.useClaudeApi,
    anthropicApiKey: config.anthropicApiKey,
    openaiApiKey: config.openaiApiKey,
  }
}];

