// Claude 또는 OpenAI 응답 파싱
const input = $input.first().json;
let suggestions = [];

try {
  let content;

  // Claude 응답 형식
  if (input.content && Array.isArray(input.content)) {
    content = input.content
      .filter(c => c.type === 'text')
      .map(c => c.text)
      .join('');
  }
  // OpenAI 응답 형식
  else if (input.choices) {
    content = input.choices[0]?.message?.content || '';
  }
  // 직접 전달된 경우
  else if (typeof input === 'string') {
    content = input;
  } else {
    content = JSON.stringify(input);
  }

  // JSON 블록 추출 (```json ... ``` 또는 직접 JSON)
  const jsonMatch = content.match(/```json\s*([\s\S]*?)```/) || 
                    content.match(/\{[\s\S]*"suggestions"[\s\S]*\}/);
  const jsonStr = jsonMatch ? (jsonMatch[1] || jsonMatch[0]) : content;

  const parsed = JSON.parse(jsonStr);
  suggestions = parsed.suggestions || [];

  // 각 제안 항목 검증/정규화
  suggestions = suggestions.map(s => ({
    category: s.category || 'ai_business',
    format: s.format || 'article',
    title: s.title || '제목 없음',
    angle: s.angle || '',
    keywords: Array.isArray(s.keywords) ? s.keywords : [],
    reference_headlines: Array.isArray(s.reference_headlines) ? s.reference_headlines : [],
    quadrant: s.quadrant || null,
    interviewee: s.interviewee || null,
  }));

} catch (err) {
  // 파싱 실패 시 빈 배열
  suggestions = [{
    category: 'ai_business',
    format: 'article',
    title: '[파싱 실패] AI 응답을 처리할 수 없습니다',
    angle: `Error: ${err.message}`,
    keywords: [],
    reference_headlines: [],
    quadrant: null,
    interviewee: null,
  }];
}

return suggestions.map(s => ({ json: s }));

// Slack 브리핑 메시지 생성
const suggestions = $input.all().map(item => item.json);
const config = $('⚙️ 설정 로드').first().json;

const emoji = { article: '📰', column: '✍️', interview: '🎙' };
const lines = ['*🗞 코아뉴스 오늘의 소재 브리핑*', ''];

if (!suggestions.length) {
  lines.push('오늘은 제안할 소재가 없습니다 (수집된 기사 부족).');
} else {
  suggestions.forEach((s, i) => {
    lines.push(`${i + 1}. ${emoji[s.format] || '📌'} *${s.title}*`);
    if (s.angle) lines.push(`   _${s.angle}_`);
    if (s.interviewee) lines.push(`   섭외 대상: ${s.interviewee}`);
    if (s.keywords?.length) lines.push(`   키워드: ${s.keywords.join(', ')}`);
    lines.push('');
  });
}

return [{
  json: {
    slackWebhookUrl: config.slackWebhookUrl,
    text: lines.join('\n'),
    suggestionsCount: suggestions.length,
  }
}];
